func FileUploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	r.Body = http.MaxBytesReader(w, r.Body, maxUploadSize)

	if err := r.ParseMultipartForm(maxUploadSize); err != nil {
		http.Error(w, "File too large or invalid form data", http.StatusBadRequest)
		return
	}

	file, header, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Failed to read file from form", http.StatusBadRequest)
		return
	}
	defer file.Close()

	if header.Size > maxUploadSize {
		http.Error(w, "File size exceeds maximum allowed size", http.StatusBadRequest)
		return
	}

	if header.Size == 0 {
		http.Error(w, "Empty file not allowed", http.StatusBadRequest)
		return
	}

	ext := strings.ToLower(filepath.Ext(header.Filename))
	if !allowedExtensions[ext] {
		http.Error(w, "File type not allowed", http.StatusBadRequest)
		return
	}

	buffer := make([]byte, 512)
	_, err = file.Read(buffer)
	if err != nil && err != io.EOF {
		http.Error(w, "Failed to read file content", http.StatusInternalServerError)
		return
	}
	_, err = file.Seek(0, 0)
	if err != nil {
		http.Error(w, "Failed to reset file pointer", http.StatusInternalServerError)
		return
	}

	mimeType := http.DetectContentType(buffer)
	if !allowedMimeTypes[mimeType] {
		http.Error(w, fmt.Sprintf("MIME type not allowed: %s", mimeType), http.StatusBadRequest)
		return
	}

	filename := sanitizeFilename(header.Filename)
	if filename == "" {
		http.Error(w, "Invalid filename", http.StatusBadRequest)
		return
	}

	randomName, err := generateRandomFilename(ext)
	if err != nil {
		http.Error(w, "Failed to generate filename", http.StatusInternalServerError)
		return
	}

	safePath := filepath.Join(uploadDir, randomName)
	cleanPath := filepath.Clean(safePath)
	if !strings.HasPrefix(cleanPath, filepath.Clean(uploadDir)+string(os.PathSeparator)) {
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	dst, err := os.OpenFile(cleanPath, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0644)
	if err != nil {
		http.Error(w, "Failed to create file", http.StatusInternalServerError)
		return
	}
	defer dst.Close()

	written, err := io.CopyN(dst, file, maxUploadSize+1)
	if err != nil && err != io.EOF {
		os.Remove(cleanPath)
		http.Error(w, "Failed to save file", http.StatusInternalServerError)
		return
	}

	if written > maxUploadSize {
		os.Remove(cleanPath)
		http.Error(w, "File size exceeds maximum allowed size", http.StatusBadRequest)
		return
	}

	relativePath := filepath.ToSlash(filepath.Join("uploads", randomName))

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, `{"success": true, "path": "/%s", "filename": "%s", "size": %d}`, 
		relativePath, sanitizeForJSON(filename), written)
}

func sanitizeFilename(filename string) string {
	filename = filepath.Base(filename)
	
	var sanitized strings.Builder
	for _, r := range filename {
		if (r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || 
			r == '.' || r == '-' || r == '_' {
			sanitized.WriteRune(r)
		}
	}
	
	result := sanitized.String()
	if len(result) == 0 || result[0] == '.' {
		return ""
	}
	
	if len(result) > 255 {
		result = result[:255]
	}
	
	return result
}

func generateRandomFilename(ext string) (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes) + ext, nil
}

func sanitizeForJSON(s string) string {
	s = strings.ReplaceAll(s, `\`, `\\`)
	s = strings.ReplaceAll(s, `"`, `\"`)
	return s
}

func ServeUploadedFile(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	requestedPath := r.URL.Path
	requestedPath = strings.TrimPrefix(requestedPath, "/uploads/")
	
	filename := filepath.Base(requestedPath)
	safePath := filepath.Join(uploadDir, filename)
	cleanPath := filepath.Clean(safePath)
	
	if !strings.HasPrefix(cleanPath, filepath.Clean(uploadDir)+string(os.PathSeparator)) {
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	fileInfo, err := os.Stat(cleanPath)
	if err != nil || fileInfo.IsDir() {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}

	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("Content-Disposition", "attachment")
	
	http.ServeFile(w, r, cleanPath)
}

